// State → primary metro fallback (every US state + DC covered).
const STATE_PRIMARY: Record<string, string> = {
  AL: "Birmingham", AK: "Anchorage", AZ: "Phoenix", AR: "Little Rock", CA: "Los Angeles", CO: "Denver",
  CT: "Hartford", DE: "Wilmington", DC: "Washington", FL: "Miami", GA: "Atlanta", HI: "Honolulu",
  ID: "Boise", IL: "Chicago", IN: "Indianapolis", IA: "Des Moines", KS: "Wichita", KY: "Louisville",
  LA: "New Orleans", ME: "Portland", MD: "Baltimore", MA: "Boston", MI: "Detroit", MN: "Minneapolis",
  MS: "Jackson", MO: "Kansas City", MT: "Billings", NE: "Omaha", NV: "Las Vegas", NH: "Manchester",
  NJ: "Newark", NM: "Albuquerque", NY: "New York", NC: "Charlotte", ND: "Fargo", OH: "Columbus",
  OK: "Oklahoma City", OR: "Portland", PA: "Philadelphia", RI: "Providence", SC: "Columbia", SD: "Sioux Falls",
  TN: "Nashville", TX: "Houston", UT: "Salt Lake City", VT: "Burlington", VA: "Richmond", WA: "Seattle",
  WV: "Charleston", WI: "Milwaukee", WY: "Cheyenne",
};

function findMetro(name: string, state: string): Metro | undefined {
  return byKey.get(`${name.toLowerCase()}|${state}`) || METROS.find((m) => m.name === name && m.state === state) || METROS.find((m) => m.name === name);
}

/** Fold a professional's (city, state) to a 100k+ metro. Never returns a town under 100k by name. */
export function foldToMetro(city: string | null | undefined, state: string | null | undefined): Metro | null {
  const st = (state || "").trim().toUpperCase();
  if (!st) return null;
  const c = (city || "").trim().toLowerCase();
  if (c) {
    const ov = SUBURB_TO_METRO[`${c}|${st.toLowerCase()}`];
    if (ov) { const m = findMetro(ov, st); if (m) return m; }
    const direct = byKey.get(`${c}|${st}`);
    if (direct) return direct;
  }
  const prim = STATE_PRIMARY[st];
  if (prim) { const m = findMetro(prim, st); if (m) return m; }
  return null;
}

export function metroLabel(m: Metro): string {
  return `${m.name}, ${m.state}`;
}
